python3 << 'PYEOF'
import json, os

# Check March 4-6 articles specifically for "hotel room" or "coastal" mentions
for month in sorted(os.listdir('articles/2026/')):
    for day in sorted(os.listdir(f'articles/2026/{month}/')):
        path = f'articles/2026/{month}/{day}/articles.jsonl'
        if not os.path.exists(path):
            continue
        with open(path) as f:
            for line in f:
                article = json.loads(line)
                title = (article.get('title') or '').lower()
                content = (article.get('content') or '')[:2000].lower() if article.get('content') else ''
                full = title + ' ' + content
                # Look for coastal Beirut districts
                if any(w in full for w in ['zaitunay', 'hamra', 'ras beirut', 'ain el mreisseh', 'mreisseh', 'raouche', 'manara', 'minet el hosn', 'verdun', 'clemenceau', 'hotel room']):
                    print(f'=== {month}/{day}: {article.get("title")} ===')
                    # Find the relevant context
                    for w in ['zaitunay', 'hamra', 'ras beirut', 'ain el mreisseh', 'mreisseh', 'raouche', 'manara', 'minet el hosn', 'verdun', 'clemenceau', 'hotel room']:
                        idx = full.find(w)
                        if idx >= 0:
                            start = max(0, idx-100)
                            end = min(len(full), idx+150)
                            print(f'  [{w}]: ...{full[start:end]}...')
                    print()
PYEOF
